package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinFactorCostModel;
import org.eclipse.rdf4j.query.explanation.TelemetryMetricNames;
import org.junit.jupiter.api.Test;

class LmdbCascadesConnectedJoinPlannerCostTieTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI MEMBER_OF = VF.createIRI("https://schema.org/memberOf");
	private static final IRI MAKES_OFFER = VF.createIRI("https://schema.org/makesOffer");
	private static final IRI PERSON = VF.createIRI("https://schema.org/Person");

	@Test
	void equalWorkSeedsPreferStrongerAccessPathBeforeFactorOrder() {
		StatementPattern weakPredicateScan = new StatementPattern(new Var("person"), new Var("memberOf", MEMBER_OF),
				new Var("org"));
		StatementPattern strongerTypeAnchor = new StatementPattern(new Var("person"), new Var("type", RDF.TYPE),
				new Var("personType", PERSON));
		StatementPattern downstream = new StatementPattern(new Var("person"), new Var("makesOffer", MAKES_OFFER),
				new Var("offer"));
		TupleExpr island = new Join(new Join(weakPredicateScan, strongerTypeAnchor), downstream);
		EqualRowsAccessPathStatistics statistics = new EqualRowsAccessPathStatistics();

		Optional<LmdbCascadesConnectedJoinPlanner.Plan> plan = LmdbCascadesConnectedJoinPlanner.plan(island, Set.of(),
				statistics, statistics);

		assertTrue(plan.isPresent());
		List<TupleExpr> orderedFactors = LmdbJoinIslandConnectivity.flattenFactors(plan.get().tupleExpr());
		assertTrue(orderedFactors.getFirst() instanceof StatementPattern,
				() -> "Expected a statement pattern first: " + orderedFactors);
		StatementPattern first = (StatementPattern) orderedFactors.getFirst();
		assertEquals(RDF.TYPE, first.getPredicateVar().getValue(),
				() -> "When rows and work tie, the connected planner should prefer the stronger physical access "
						+ "path instead of falling back to factor order: " + orderedFactors);
	}

	private static final class EqualRowsAccessPathStatistics extends EvaluationStatistics
			implements JoinFactorCostModel {

		@Override
		public double getCardinality(TupleExpr expr) {
			return 60_000.0d;
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			if (!(factor instanceof StatementPattern pattern)) {
				return Optional.of(new FactorCostEstimate(60_000.0d, 60_000.0d));
			}
			boolean strongAccessPath = RDF.TYPE.equals(pattern.getPredicateVar().getValue());
			Map<String, String> stringMetrics = Map.of(
					TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE, "prefixScan",
					TelemetryMetricNames.PLANNED_INDEX_NAME, strongAccessPath ? "posc" : "spoc");
			Map<String, Double> doubleMetrics = Map.of(
					TelemetryMetricNames.PLANNED_INDEX_PREFIX_LENGTH, strongAccessPath ? 2.0d : 1.0d,
					TelemetryMetricNames.PLANNED_ACCESS_ROWS, 60_000.0d,
					TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, strongAccessPath ? 60_000.0d : 120_000.0d,
					TelemetryMetricNames.PLANNED_ACCESS_PATH_CANDIDATES, 3.0d);
			return Optional.of(new FactorCostEstimate(60_000.0d, 60_000.0d, stringMetrics, doubleMetrics));
		}
	}
}
